+            ) {
+                let mut all = plains;
+                all.extend(patterns);
+                let (split_plain, split_patterns) = split_patterns(&all);
+                assert_eq!(
+                    split_plain.len() + split_patterns.len(),
+                    all.len(),
+                    "partition should be complete"
+                );
+                for p in &split_patterns {
+                    assert!(is_pattern(p));
+                }
+            }
+
+            /// `hex_encode` output length is always 2x input length.
